prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?flow ?flowName ?source ?sourceName ?target ?targetName WHERE {
  ?flow a bbo:SequenceFlow .
  ?flow bbo:has_targetRef ?target .
  ?target bbo:name "Complaint rejected" .
  ?flow bbo:has_sourceRef ?source .
  OPTIONAL { ?flow bbo:name ?flowName . }
  OPTIONAL { ?source bbo:name ?sourceName . }
  OPTIONAL { ?target bbo:name ?targetName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?source ?type ?name ?gatewayDirection ?default WHERE {
  VALUES ?source { <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-966B51A2-C839-41C1-9018-3699EAEBC86E> }
  ?source a ?type .
  OPTIONAL { ?source bbo:name ?name . }
  OPTIONAL { ?source bboExt:gatewayDirection ?gatewayDirection . }
  OPTIONAL { ?source bboExt:default ?default . }
}
LIMIT 25
